import{d,r as l,c as v,a as e,b as t,w as s,e as o,o as c,f as i,p,g as r,_ as g}from"./index-95246ce0.js";const u=n=>(p("data-v-32318528"),n=n(),r(),n),_={class:"culture-detail-page"},h={class:"home-header"},m=u(()=>e("div",{class:"logo"},[e("h1",null,"山河桥语"),e("p",null,"中国古代桥梁时空数据可视化")],-1)),f={class:"nav-menu"},b=o('<main class="detail-content" data-v-32318528><section class="detail-header" data-v-32318528><h2 data-v-32318528>卢沟桥</h2><p data-v-32318528>中国古代最长的联拱石桥，以石狮雕刻闻名</p></section><section class="detail-section" data-v-32318528><div class="section-content" data-v-32318528><h3 data-v-32318528>基本信息</h3><div class="info-grid" data-v-32318528><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>中文名</span><span class="info-value" data-v-32318528>卢沟桥</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>别名</span><span class="info-value" data-v-32318528>芦沟桥</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>地理位置</span><span class="info-value" data-v-32318528>北京市丰台区宛平城</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>建造时间</span><span class="info-value" data-v-32318528>金大定二十九年（1189年）</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>建成时间</span><span class="info-value" data-v-32318528>金明昌三年（1192年）</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>桥梁类型</span><span class="info-value" data-v-32318528>联拱石桥</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>桥梁长度</span><span class="info-value" data-v-32318528>266.5米</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>桥梁宽度</span><span class="info-value" data-v-32318528>9.3米</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>桥墩数量</span><span class="info-value" data-v-32318528>10个</span></div><div class="info-item" data-v-32318528><span class="info-label" data-v-32318528>保护级别</span><span class="info-value" data-v-32318528>全国重点文物保护单位</span></div></div></div></section><section class="detail-section" data-v-32318528><div class="section-content" data-v-32318528><h3 data-v-32318528>历史沿革</h3><p data-v-32318528>卢沟桥始建于金大定二十九年（1189年），建成于金明昌三年（1192年）。</p><p data-v-32318528>在历史上，卢沟桥经历了多次修缮：</p><ul data-v-32318528><li data-v-32318528><strong data-v-32318528>明正统九年（1444年）</strong>：进行了修缮。</li><li data-v-32318528><strong data-v-32318528>明弘治三年（1490年）</strong>：进行了修缮。</li><li data-v-32318528><strong data-v-32318528>明嘉靖三十四年（1555年）</strong>：因地震损坏，进行了修缮。</li><li data-v-32318528><strong data-v-32318528>清康熙年间（1662-1722年）</strong>：进行了修缮。</li><li data-v-32318528><strong data-v-32318528>清乾隆年间（1736-1795年）</strong>：进行了修缮。</li><li data-v-32318528><strong data-v-32318528>1937年7月7日</strong>：卢沟桥事变发生，卢沟桥成为中国人民抗日战争的起点。</li><li data-v-32318528><strong data-v-32318528>1986-1987年</strong>：对卢沟桥进行了全面的修缮，恢复了其历史原貌。</li></ul></div></section><section class="detail-section" data-v-32318528><div class="section-content" data-v-32318528><h3 data-v-32318528>建筑特色</h3><p data-v-32318528>卢沟桥是中国古代最长的联拱石桥，其建筑特色主要体现在以下几个方面：</p><h4 data-v-32318528>1. 联拱结构</h4><p data-v-32318528>卢沟桥采用了联拱结构，共有11个拱洞，拱洞的大小和间距经过精心设计，既美观又实用。</p><h4 data-v-32318528>2. 石狮雕刻</h4><p data-v-32318528>卢沟桥的石狮雕刻是其最著名的特色，桥两侧的石栏上雕刻着501个形态各异的石狮，每只石狮的姿态和表情都不相同，体现了中国古代雕刻艺术的高超水平。</p><h4 data-v-32318528>3. 桥墩设计</h4><p data-v-32318528>卢沟桥的桥墩设计成尖劈形，这种设计可以减少水流对桥墩的冲击力，增强桥梁的稳定性。</p><h4 data-v-32318528>4. 桥面结构</h4><p data-v-32318528>卢沟桥的桥面由石板铺成，石板之间用铁榫连接，增强了桥面的整体性和稳定性。</p></div></section><section class="detail-section" data-v-32318528><div class="section-content" data-v-32318528><h3 data-v-32318528>历史意义</h3><p data-v-32318528>卢沟桥在中国桥梁史上具有重要的历史意义：</p><ul data-v-32318528><li data-v-32318528>它是中国古代最长的联拱石桥，体现了中国古代桥梁建筑的高超技艺。</li><li data-v-32318528>它以其精美的石狮雕刻而闻名，是中国古代雕刻艺术的杰作。</li><li data-v-32318528>它是中国近代史上的重要历史事件发生地，1937年7月7日的卢沟桥事变标志着中国全民族抗战的开始。</li><li data-v-32318528>它是中国古代科技成就的重要代表，被列为全国重点文物保护单位。</li></ul></div></section><section class="detail-section" data-v-32318528><div class="section-content" data-v-32318528><h3 data-v-32318528>文化内涵</h3><p data-v-32318528>卢沟桥不仅是一座实用的交通设施，也是中国传统文化的重要象征：</p><h4 data-v-32318528>1. 石狮文化</h4><p data-v-32318528>卢沟桥的石狮雕刻是中国古代雕刻艺术的杰作，每只石狮都有其独特的造型和寓意，体现了中国传统文化的丰富内涵。</p><h4 data-v-32318528>2. 卢沟桥事变</h4><p data-v-32318528>1937年7月7日的卢沟桥事变是中国近代史上的重要事件，标志着中国全民族抗战的开始，卢沟桥因此成为了中国人民抗日战争的象征。</p><h4 data-v-32318528>3. 文学作品</h4><p data-v-32318528>卢沟桥是中国文学作品中经常描绘的场景，如清代诗人爱新觉罗·弘历的《卢沟晓月》等。</p></div></section><section class="detail-section" data-v-32318528><div class="section-content" data-v-32318528><h3 data-v-32318528>桥梁图片</h3><div class="image-gallery" data-v-32318528><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Lugou%20Bridge%20ancient%20stone%20arch%20bridge%20in%20Beijing%2C%20Jinan%20Dynasty%2C%20stone%20lions%20on%20rails%2C%20full%20view&amp;image_size=landscape_16_9" alt="卢沟桥全景" class="gallery-image" data-v-32318528><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Lugou%20Bridge%20stone%20lions%20close%20up%2C%20ancient%20Chinese%20bridge%2C%20intricate%20carvings&amp;image_size=landscape_16_9" alt="卢沟桥石狮" class="gallery-image" data-v-32318528><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Lugou%20Bridge%20arch%20structure%2C%20ancient%20Chinese%20bridge%2C%20stone%20construction&amp;image_size=landscape_16_9" alt="卢沟桥拱洞" class="gallery-image" data-v-32318528></div></div></section></main><footer class="page-footer" data-v-32318528><p data-v-32318528>© 2026 山河桥语 - 中国古代桥梁时空数据可视化</p></footer>',2),C=d({__name:"BridgeLugouPage",setup(n){return(B,x)=>{const a=l("router-link");return c(),v("div",_,[e("header",h,[m,e("nav",f,[t(a,{to:"/",class:"nav-item"},{default:s(()=>[i("首页")]),_:1}),t(a,{to:"/visualization",class:"nav-item"},{default:s(()=>[i("数据可视化")]),_:1}),t(a,{to:"/culture",class:"nav-item active"},{default:s(()=>[i("文化介绍")]),_:1}),t(a,{to:"/statistics",class:"nav-item"},{default:s(()=>[i("数据统计")]),_:1}),t(a,{to:"/about",class:"nav-item"},{default:s(()=>[i("关于项目")]),_:1})])]),b])}}});const L=g(C,[["__scopeId","data-v-32318528"]]);export{L as default};
